package main

import (
	"fmt"
	"io"
	"net/http"
)

func main() {
	// The URL we want to request data from
	url := "https://jsonplaceholder.typicode.com/todos/1"

	fmt.Printf("Making request to: %s\n\n", url)

	// 1. Make the HTTP GET request
	resp, err := http.Get(url)
	if err != nil {
		fmt.Printf("Error making the request: %v\n", err)
		return
	}
	// 2. Ensure the response body is closed when we are done with it
	defer resp.Body.Close()

	// 3. Check if the request was successful (status code 200-299)
	if resp.StatusCode != http.StatusOK {
		fmt.Printf("Received non-successful status code: %d\n", resp.StatusCode)
		return
	}

	// 4. Read the entire response body
	body, err := io.ReadAll(resp.Body)
	if err != nil {
		fmt.Printf("Error reading the response body: %v\n", err)
		return
	}

	// 5. Print the content
	fmt.Println("--- Request Content (Response Body) ---")
	fmt.Println(string(body))
	fmt.Println("--------------------------------------")
}
```

